ui.debug.addRules("nuribou",[{rules:"Shade some cells on the board to form regions of unshaded cells.\n1. Each region contains exactly one number.\n2. A number indicates the size of the region that contains it.\n3. You cannot shade a cell with a number.\n4. Shaded cells must form rectangular blocks with a width of 1.\n5. Two blocks of the same size cannot be diagonally adjacent.",history:"This genre first appeared in Puzzle Communication Nikoli vol. 68."},{rules:"盤面のいくつかの白マス全体を黒く塗り、黒マスとします。\n1. 数字が入っているマスは黒マスになりません。\n2. 数字は、その数字が含まれる、黒マスによって分断されたところ (シマとよぶ)のマスの数です。\n3. すべてのシマには数字が１つずつ入っていなければなりません。\n4. 黒マスは、幅１マス、長さ１マス以上のカタマリになります。\n5. 同じ面積の黒マスのカタマリは、角を共有しません。",history:"パズル通信ニコリ vol.68より"}]),ui.debug.addDebugData("nuribou",{url:"5/5/1g2l1g4r7",failcheck:[["csWidthGt1","pzprv3/nuribou/5/5/1 . 2 . . /. . . . 1 /. 4 . . . /. . . . . /. . . . 7 /. . . . . /# # # . . /. . # . . /. . # . . /. . . . . /"],["csCornerSize","pzprv3/nuribou/5/5/1 . 2 . . /. . . . 1 /. 4 . . . /. . . . . /. . . . 7 /+ # + + # /# + # # + /. . + + # /. . . . . /. . . . . /"],["bkNoNum","pzprv3/nuribou/5/5/1 . 2 . . /. . . . 1 /. 4 . . . /. . . . . /. . . . 7 /+ # + + # /# + # # + /# + + + # /. # . . . /. . # # . /"],["bkNumGe2","pzprv3/nuribou/5/5/1 . 2 . . /. . . . 1 /. 4 . . . /. . . . . /. . . . 7 /+ # + + # /# + # # + /# + + + # /. . . . . /. . . . . /"],["bkSizeNe","pzprv3/nuribou/5/5/1 . 2 . . /. . . . 1 /. 4 . . . /. . . . . /. . . . 7 /+ # + # . /+ # + # + /# + # . # /. . # . . /. . # . . /"],[null,"pzprv3/nuribou/5/5/1 . 2 . . /. . . . 1 /. 4 . . . /. . . . . /. . . . 7 /+ # + + # /# + # # + /# + + + # /+ # # # . /. . . . . /"]],inputs:[]});
